SELECT ts_pivot.timestamp AS timestamp, count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS sample_count, (count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(ts_pivot._inner_rows) / CAST(count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS DECIMAL) AS rows_per_sample, sum(ts_pivot."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(ts_pivot."up__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(ts_pivot."up__out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings" FROM (SELECT ts_flat.bldg_id AS bldg_id, ts_flat.state AS state, ts_flat.timestamp AS timestamp, sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 0) AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 1) AS "up__out.electricity.total.energy_consumption", count(*) FILTER (WHERE ts_flat.upgrade = 0) AS _inner_rows FROM (SELECT comstock_amy2018_r2_2025_ts_by_state.bldg_id AS bldg_id, comstock_amy2018_r2_2025_ts_by_state.state AS state, date_trunc('month', date_add('second', -900, comstock_amy2018_r2_2025_ts_by_state.timestamp)) AS timestamp, comstock_amy2018_r2_2025_ts_by_state.upgrade AS upgrade, comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state WHERE comstock_amy2018_r2_2025_ts_by_state.upgrade IN (0, 1) AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO' AND (comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state) IN (SELECT bs.bldg_id, bs.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade IN (1) AND bs.applicability = true GROUP BY bs.bldg_id, bs.state HAVING count(distinct(bs.upgrade)) = 1)) AS ts_flat GROUP BY ts_flat.bldg_id, ts_flat.state, ts_flat.timestamp) AS ts_pivot JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.state = ts_pivot.state AND bs.upgrade = 0 AND bs.state = 'CO' GROUP BY 1 ORDER BY 1